VALUES
  ('real-estate-appraiser-moex-00423', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '根據甲段文章，下列敘述不正確的選項是：', '["精妙的學問與技藝常是「雖在父兄，不能以移子弟」", "本篇的「得手應心」近於〈庖丁解牛〉中「遊刄有餘」之意", "讀書與技藝皆重於個人的自覺自證，不能只依賴別人的傳授", "輪扁說桓公讀的是糟魄，是在批評桓公讀的書太淺薄，不夠深入"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00424', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '根據乙段文章，下列敘述正確的選項是：', '["李公擇年少好讀書，年長就丟下九千餘卷藏書，下山去了", "李公擇讀的書「未嘗少損」，可見並未用心投入，好好研讀", "蘇東坡感嘆：古人想讀書而很難看到書，現在的人有書而不讀", "蘇東坡旅遊至廬山，發現李氏山房這一人文景點，所以寫了這篇文章"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00425', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '人間事理往往因觀點不同而說法不同。上述兩段材料各有不同的讀書觀點，兩段材料都有價值，問題是能 否判別情境適時活用。設想如需借用上兩段材料中的一段，分別運用在下列三種情境中：', '["為鼓勵青少年多閱讀時", "與一個食古不化的書呆子談讀書的藝術時", "某圖書館想以一則故事為徵募圖書宣傳時 各用那一段材料取義闡發較為合適？", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00426', 'real-estate-appraiser', 'real-estate-appraiser-moex-099-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '根據上文內容判斷，下列敘述正確的選項是？', '["作者贊同史基納的行為主義學派理論", "作者大致贊同心理學家布萊爾的看法", "作者對史基納和布萊爾都有不同意見", "作者同意布萊爾但又提出修正的看法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:06+00:00", "source_pdf_sha1": "aa2715d75041", "answer_pdf_sha1": "54154d8d65c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "905", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
